-- ===== Dev Fixture Major B 2025 =====
WITH season AS (SELECT s.id FROM seasons s JOIN titles t ON t.id = s.title_id WHERE s.year = 2025 AND t.short_name = 'BO6' AND s.league = 'CDL')
INSERT INTO events (season_id, name, tier, start_date, end_date, location, is_lan, prize_pool)
SELECT id, 'Dev Fixture Major B 2025', 'S', '2025-03-15', '2025-03-15'::date + 2, 'Boston, MA', true, 500000 FROM season;

INSERT INTO stages (event_id, name, ordinal)
SELECT id, 'Winners Bracket', 0 FROM events WHERE name = 'Dev Fixture Major B 2025';
INSERT INTO stages (event_id, name, ordinal)
SELECT id, 'Losers Bracket', 1 FROM events WHERE name = 'Dev Fixture Major B 2025';
INSERT INTO stages (event_id, name, ordinal)
SELECT id, 'Grand Final', 2 FROM events WHERE name = 'Dev Fixture Major B 2025';

WITH stg AS (SELECT s.id, s.event_id FROM stages s JOIN events e ON e.id = s.event_id WHERE e.name = 'Dev Fixture Major B 2025' AND s.name = 'Winners Bracket')
INSERT INTO series (stage_id, event_id, team1_id, team2_id, team1_score, team2_score, best_of, played_at, round_label, liquipedia_match_id)
SELECT stg.id, stg.event_id, t1.id, t2.id, 2, 3, 5, '2025-03-15'::date + 0 + time '12:00' + interval '0 hours', 'WB R1', 'dev-ev1s0'
FROM stg, teams t1, teams t2 WHERE t1.name = 'OpTic Texas' AND t2.name = 'LA Thieves';

