SELECT stg.id, stg.event_id, t1.id, t2.id, 1, 3, 5, '2025-03-15'::date + 1 + time '12:00' + interval '2 hours', 'LB Final', 'dev-ev1s4'
FROM stg, teams t1, teams t2 WHERE t1.name = 'LA Thieves' AND t2.name = 'Atlanta FaZe';

