SELECT stg.id, stg.event_id, t1.id, t2.id, 3, 2, 5, '2025-03-15'::date + 1 + time '12:00' + interval '4 hours', 'Grand Final', 'dev-ev1s5'
FROM stg, teams t1, teams t2 WHERE t1.name = 'Toronto Ultra' AND t2.name = 'Atlanta FaZe';

